interface Flyable {
    void fly();
    default void land() { System.out.println("Landing"); }
}

abstract class Animal {
    String name;
    abstract void speak();
}

class Bird extends Animal implements Flyable {
    void speak() { System.out.println("Chirp"); }
    public void fly() { System.out.println("Flying"); }
}

class Parent {
    static void print() { System.out.println("Parent"); }
}
class Child extends Parent {
    static void print() { System.out.println("Child"); }
}
public class Main {
    public static void main(String[] args) {
        Parent p = new Child();
        p.print(); // Prints 'Parent', not 'Child'!
    }
}

interface A { default void show() { System.out.println("A"); } }
interface B { default void show() { System.out.println("B"); } }

class C implements A, B {
    @Override
    public void show() {
        // Explicitly resolving the ambiguity
        A.super.show();
        B.super.show();
    }
}

