interface Greeting {
    void sayHello();
}

public class Main {
    public static void main(String[] args) {
        // Anonymous inner class implementing Greeting
        Greeting g = new Greeting() {
            @Override
            public void sayHello() { System.out.println("Hello World"); }
        };
        g.sayHello();
    }
}

public final class ImmutableUser {
    private final String name;
    private final List<String> roles;

    public ImmutableUser(String name, List<String> roles) {
        this.name = name;
        this.roles = new ArrayList<>(roles); // Deep copy on assign
    }

    public List<String> getRoles() {
        return new ArrayList<>(roles); // Return copy, protecting internal state
    }
}

class Employee implements Cloneable {
    String name;
    Department dept; // Mutable reference

    @Override
    protected Object clone() throws CloneNotSupportedException {
        Employee cloned = (Employee) super.clone();
        cloned.dept = new Department(this.dept.name); // Deep copy step
        return cloned;
    }
}
